#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, A, B;
        scanf("%lld", &X);
        scanf("%lld %lld", &A, &B);
        if (X >= A + B) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

